import itertoolsfrom threeML import JointLikelihoodclass JL():        def jl_info(self, start_values):                self.start_values = start_values        self.method = 'joint_likelihood'        self.method_short = 'jl'                return            def perform_fit(self, i):                jl = JointLikelihood(self.model.model, self.model.grb.data[i])        _ = jl.fit()                return jl            def add_to_df(self, index, ar):                for key, (k, param) in itertools.product(self._results.keys(), enumerate(self.free_parameters)):            self._results[key].at[index, param] = ar._get_results_table(error_type = 'covariance', cl = 0.68, covariance = ar.covariance_matrix).frame[key].iloc[k]                return